# scripts/check_dependency_allowlist.py
import json, subprocess, sys
from pathlib import Path

allowlist_path = Path(".approved-dependencies/allowlist.json")
allowlist = {e["name"]: e for e in json.loads(allowlist_path.read_text())["approved"]}

# Resolve installed packages (works in a venv)
result = subprocess.run(
    ["pip", "list", "--format=json"],
    capture_output=True, text=True, check=True
)
installed = {pkg["name"].lower(): pkg["version"] for pkg in json.loads(result.stdout)}

violations = []
for name, version in installed.items():
    if name not in allowlist:
        violations.append(f"UNAPPROVED: {name}=={version} — not in allowlist")

if violations:
    for v in violations:
        print(v)
    sys.exit(1)

print(f"Allowlist check passed: {len(installed)} packages, 0 violations")

# scripts/check_version_pins.py
import json, re, sys
from pathlib import Path

allowlist = {e["name"]: e for e in json.loads(
    Path(".approved-dependencies/allowlist.json").read_text())["approved"]}

# Parse requirements.txt style pins
pins = {}
for line in Path("requirements.txt").read_text().splitlines():
    line = line.strip()
    if not line or line.startswith("#"):
        continue
    m = re.match(r"([a-zA-Z0-9_\-]+)==(.+)", line)
    if m:
        pins[m.group(1).lower()] = m.group(2)

violations = []
for name, entry in allowlist.items():
    if entry["tier"] >= 2 and name in pins:
        # Exact pin present — good
        continue
    elif entry["tier"] >= 2 and name not in pins:
        violations.append(
            f"NOT PINNED: {name} (Tier {entry['tier']}) must be exactly pinned"
        )

if violations:
    for v in violations:
        print(v)
    sys.exit(1)

print("Version pin check passed")
